var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 개인 기록 재구성","JPN":"CN No. VCDF001D003526-63\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: 対象者私記再構成","ENG":"CN No. VCDF001D003526-63\\n<color=#ffd34c>Priority-1 Subject</color> Authorized Viewing Material\\nAppendix: Reconstruction of Subject's Personal Records","TWN":"(TWN)CN No. VCDF001D003526-63\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 개인 기록 재구성"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아버지.","JPN":"父。","ENG":"Father.","TWN":"(TWN)아버지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이 시간에 웬 손님인가 했더니 너였구나, 베네딕트. 밤도 늦었는데 무슨 일이니.","JPN":"この時間になんというお客様かしたら君だったな、ベネディクト。夜も遅かったが何かだから。","ENG":"To think it was you, Benedict. I was wondering who would be visiting at this hour. It's late. What brings you here?","TWN":"(TWN)이 시간에 웬 손님인가 했더니 너였구나, 베네딕트. 밤도 늦었는데 무슨 일이니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"책을 읽다가 모르는 부분이 있어서 여쭤 보려고 했습니다.","JPN":"本を読んで知らない部分があってお聞きしようとしました。","ENG":"I was reading a book and came across something I didn't understand. I wanted to ask you about it.","TWN":"(TWN)책을 읽다가 모르는 부분이 있어서 여쭤 보려고 했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"네 나이에 자정까지 책을 읽는 건 좋은 게 아닐 것 같구나.","JPN":"はい年齢に午前０時まで本を読むのは良いのではないようであるね。","ENG":"Reading until midnight at your age doesn't seem like a good idea.","TWN":"(TWN)네 나이에 자정까지 책을 읽는 건 좋은 게 아닐 것 같구나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 나는 네 아버지다.","JPN":"そして出る君の父だ。","ENG":"And I am your father.","TWN":"(TWN)그리고 나는 네 아버지다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"딱딱하게 격식을 차리지 않아도 돼. 내가 부담을 줬는지 걱정스럽구나.","JPN":"固く格式を整えなくてもよい。私が負担を与えたのか憂わしいね。","ENG":"You don't need to be so rigid and formal. I worry that I've made you feel pressured.","TWN":"(TWN)딱딱하게 격식을 차리지 않아도 돼. 내가 부담을 줬는지 걱정스럽구나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"......아뇨. 아니에요. 아버지.","JPN":"......いいえ。いいえ。父。","ENG":"......No. It's not that. Father.","TWN":"(TWN)......아뇨. 아니에요. 아버지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그래. 어차피 방으로 가도 혼자 답을 찾느라 한참 뒤척거리겠지.","JPN":"そう。どのみち部屋に行っても一人で答えを探すためにしばらく掻き回す。","ENG":"Well. You'd probably just go back to your room and struggle alone trying to find the answer for hours anyway.","TWN":"(TWN)그래. 어차피 방으로 가도 혼자 답을 찾느라 한참 뒤척거리겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"같이 보자. 모르는 부분이 어떤 곳이니.","JPN":"一緒に見よう。知らない部分がどのような所だから。","ENG":"Let's look at it together. What part don't you understand?","TWN":"(TWN)같이 보자. 모르는 부분이 어떤 곳이니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"영지주의에 대해서입니다.","JPN":"領地主義に対したからです。","ENG":"It's about Gnosticism.","TWN":"(TWN)영지주의에 대해서입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"이단 사상 말이구나. 네게는 아직 이해하기 어려운 이야기겠지.","JPN":"異端思想言葉だな。君にはまだ理解しにくい話だろう。","ENG":"Heretical teachings, you mean. It must be a difficult subject for you to understand at your age.","TWN":"(TWN)이단 사상 말이구나. 네게는 아직 이해하기 어려운 이야기겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"영지주의는 선택된 이들만 구원 받을 수 있다고 한단다.","JPN":"領地主義は選択されたこれらだけ救援されることができると言うという。","ENG":"Gnosticism says that only the chosen few can receive salvation.","TWN":"(TWN)영지주의는 선택된 이들만 구원 받을 수 있다고 한단다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"내면의 영성을 각성한 자들만이 추악한 현실에서 벗어나 해방된 세계에 속할 수 있다는 뜻이지.","JPN":"内面の霊性を目覚めた者だけが醜悪な現実から脱して解放された世界に属すことができるという意味だ。","ENG":"It means that only those who have awakened their inner spirituality can escape from this ugly reality and belong to the liberated world.","TWN":"(TWN)내면의 영성을 각성한 자들만이 추악한 현실에서 벗어나 해방된 세계에 속할 수 있다는 뜻이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 베네딕트, 구원의 기회는 모두에게 주어지는 것이다.","JPN":"しかしベネディクト、救援の機会は皆に与えられるのである。","ENG":"But Benedict, the opportunity for salvation is given to everyone.","TWN":"(TWN)하지만 베네딕트, 구원의 기회는 모두에게 주어지는 것이다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"너나, 나나, 찬송가가 싫다고 악을 쓰는 옆집 할아버지까지.","JPN":"君や、ナナ、賛美歌が嫌いであるとわめく隣家お爺さんまで。","ENG":"Whether it's you, me, or even the old man next door who curses because he hates hymns.","TWN":"(TWN)너나, 나나, 찬송가가 싫다고 악을 쓰는 옆집 할아버지까지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"현실은 벗어나야 할 곳이 아니란다. 더 아름답게 가꿀 수 있는 곳이지.","JPN":"現実は脱しなければならない所ではないそうだ。さらに美しく作ることができる所だ。","ENG":"Reality isn't something we need to escape from. It's something we can cultivate to be more beautiful.","TWN":"(TWN)현실은 벗어나야 할 곳이 아니란다. 더 아름답게 가꿀 수 있는 곳이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"간단히 말하면, 인 거죠?","JPN":"早い話が、であることですか?","ENG":"In simple terms, it's about people, right?","TWN":"(TWN)간단히 말하면, 인 거죠?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"그래. 간단히 말하면 그렇지.","JPN":"そう。早い話がそうなの。","ENG":"Yes. In simple terms, that's right.","TWN":"(TWN)그래. 간단히 말하면 그렇지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"너무 일찍, 너무 많은 것을 접하게 되면 갈피를 잡지 못하고 흔들리게 된단다. ","JPN":"とても早く、あまりにも多いのを接するようになればページを殺すことができなくて揺れるようになるという。","ENG":"If you encounter too much, too soon, you'll lose your bearings and falter.","TWN":"(TWN)너무 일찍, 너무 많은 것을 접하게 되면 갈피를 잡지 못하고 흔들리게 된단다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 이 아비처럼 주님의 뜻을 따르지 않아도 좋다. 하지만 바른 길을 갔으면 하는구나. ","JPN":"君がこのアビのように神様の意味に従わなくても良い。しかし正しい道に行ったらと思うのね。","ENG":"You don't have to follow the Lord's will as I do. But I hope you walk the right path.","TWN":"(TWN)네가 이 아비처럼 주님의 뜻을 따르지 않아도 좋다. 하지만 바른 길을 갔으면 하는구나. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 아버지처럼 사제가 될 거예요.","JPN":"私はお父さんのように師弟になるはずであるです。","ENG":"I'm going to become a priest like you, Father.","TWN":"(TWN)저는 아버지처럼 사제가 될 거예요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"보기보다 힘든 일이란다.","JPN":"表示より大変な事だそうだ。","ENG":"It's harder than it looks.","TWN":"(TWN)보기보다 힘든 일이란다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 사람들을 돕고 싶어요. 아버지가 저를 도와 주신 것처럼.","JPN":"私は人々を助けたいです。お父さんが私を助けてくれたように。","ENG":"I want to help people. Just like you helped me.","TWN":"(TWN)저는 사람들을 돕고 싶어요. 아버지가 저를 도와 주신 것처럼."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":".......","JPN":".......","ENG":".......","TWN":"(TWN)......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"밤이 깊었구나. 자, 이제 자러 가자꾸나.","JPN":"夜が深かったな。さあ、もう寝に行こう。","ENG":"The night has grown deep. Come, let's get you to bed.","TWN":"(TWN)밤이 깊었구나. 자, 이제 자러 가자꾸나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};